#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <vector>
#include <iostream>
#include <cuda_runtime.h>

// Inline definitions from headers to avoid missing files
typedef struct {
    float lat;
    float lng;
} LatLong;

typedef struct {
    char recString[49];
    float distance;
} Record;

#define REC_LENGTH 49

// CUDA Kernel equivalent to OpenCL NearestNeighbor
__global__ void NearestNeighbor(LatLong *d_locations,
                                float *d_distances,
                                const int numRecords,
                                const float lat,
                                const float lng) {
    int globalId = threadIdx.x + blockIdx.x * blockDim.x;

    if (globalId < numRecords) {
        LatLong *latLong = d_locations + globalId;
        float *dist = d_distances + globalId;
        float diffLat = lat - latLong->lat;
        float diffLng = lng - latLong->lng;
        *dist = sqrtf(diffLat * diffLat + diffLng * diffLng);
    }
}

// Helper functions mimicking the OpenCL utility behavior for CUDA
void checkCudaError(cudaError_t status, const char *msg, bool exitOnErr) {
    if (status != cudaSuccess) {
        printf("CUDA Error: %d %s %s\n", status, cudaGetErrorString(status), msg);
        if (exitOnErr) {
            exit(-1);
        }
    }
}

void* alloc(size_t size) {
    void* ptr = malloc(size);
    if (ptr == NULL) {
        perror("malloc");
        exit(-1);
    }
    return ptr;
}

// Mocking cl_init_context for CUDA environment
void cuda_init_context(int platform, int dev, int quiet) {
    cudaDeviceProp prop;
    int deviceCount;
    cudaError_t err = cudaGetDeviceCount(&deviceCount);
    checkCudaError(err, "Getting device count", true);

    if (deviceCount == 0) {
        printf("No CUDA devices found\n");
        exit(-1);
    }
    int chosen_device = 0;
    // Only use provided device if both platform and device are specified logically
    // In CUDA, platform is ignored, but we respect the 'dev' argument if valid
    if (dev >= 0 && dev < deviceCount) {
        chosen_device = dev;
    }

    err = cudaSetDevice(chosen_device);
    checkCudaError(err, "Setting device", true);

    err = cudaGetDeviceProperties(&prop, chosen_device);
    checkCudaError(err, "Getting device properties", true);

    if (!quiet) {
        printf("Using Device %d: %s\n", chosen_device, prop.name);
    }
}

cudaStream_t getCommandQueue() {
    return cudaStreamDefault;
}

void cuda_sync() {
    cudaDeviceSynchronize();
}

// Main logic translated from OpenCL to CUDA
float *CudaFindNearestNeighbors(
    int numRecords,
    std::vector<LatLong> &locations,
    float lat,
    float lng,
    int timing) {

    LatLong *d_locations = NULL;
    float *d_distances = NULL;
    cudaError_t error;

    if (numRecords == 0) {
        return (float*)malloc(sizeof(float));
    }

    size_t loc_size = sizeof(LatLong) * numRecords;
    size_t dist_size = sizeof(float) * numRecords;

    error = cudaMalloc(&d_locations, loc_size);
    checkCudaError(error, "Creating buffer locations", true);

    error = cudaMalloc(&d_distances, dist_size);
    checkCudaError(error, "Creating buffer distances", true);

    cudaStream_t command_queue = getCommandQueue();

    error = cudaMemcpy(d_locations, &locations[0], loc_size, cudaMemcpyHostToDevice);
    checkCudaError(error, "Writing buffer locations", true);

    // Setup kernel arguments (implicit in CUDA via direct call)
    int blockSize = 64;
    int numBlocks = (numRecords + blockSize - 1) / blockSize;

    NearestNeighbor<<<numBlocks, blockSize>>>(d_locations, d_distances, numRecords, lat, lng);
    error = cudaGetLastError();
    checkCudaError(error, "ERROR in Executing Kernel NearestNeighbor", true);

    // Ensure kernel completion before reading
    cudaDeviceSynchronize();

    float *distances = (float *)malloc(dist_size);
    if (!distances) {
        printf("Failed to allocate host memory for results\n");
        exit(-1);
    }

    error = cudaMemcpy(distances, d_distances, dist_size, cudaMemcpyDeviceToHost);
    checkCudaError(error, "ERROR with cudaMemcpy", true);

    if (timing) {
        printf("# Records\tWrite(s) [size]\t\tKernel(s)\tRead(s)  [size]\t\tTotal(s)\n");
        printf("%d        \t", numRecords);
        // Simplified timing for CUDA
        printf("N/A\tN/A\tN/A\tN/A\n");
    }

    cudaFree(d_locations);
    cudaFree(d_distances);

    return distances;
}

int loadData(char *filename, std::vector<Record> &records, std::vector<LatLong> &locations) {
    FILE *flist, *fp;
    int i = 0;
    char dbname[64], db_fullname[128];
    int recNum = 0;
    char *data_folder = getenv("DATA_FOLDER");
    char default_folder[] = ".";
    if (!data_folder) data_folder = default_folder;

    flist = fopen(filename, "r");
    if (!flist) {
        fprintf(stderr, "error reading filelist: %s\n", filename);
        exit(0);
    }

    while (!feof(flist)) {
        if (fscanf(flist, "%s\n", dbname) != 1) {
            // Handle potential trailing newline or empty line
            if (feof(flist)) break;
            fprintf(stderr, "error reading filelist entry\n");
            exit(0);
        }
        sprintf(db_fullname, "%s/%s", data_folder, dbname);
        fp = fopen(db_fullname, "r");
        if (!fp) {
            printf("error opening a db (%s)\n", db_fullname);
            // Don't exit immediately if one file fails, or exit depending on strictness. 
            // Original code exits.
            exit(1);
        }

        while (!feof(fp)) {
            Record record;
            LatLong latLong;
            // Initialize struct
            memset(record.recString, 0, REC_LENGTH);
            record.distance = 0.0f;
            latLong.lat = 0.0f;
            latLong.lng = 0.0f;

            if (fgets(record.recString, REC_LENGTH, fp) == NULL) break;

            // The original code does fgetc(fp) to consume a delimiter? 
            // Actually, fgets reads until newline. The original code might be handling specific formatting.
            // Let's stick to standard line reading.

            if (strlen(record.recString) < 38) { 
                // Skip malformed lines if too short for the parsing logic below
                continue; 
            }

            char substr[6];
            // Parse latitude: chars 28-32 (5 chars)
            for(i = 0; i < 5; i++) {
                if (28+i < strlen(record.recString))
                    substr[i] = *(record.recString + i + 28);
                else 
                    substr[i] = ' ';
            }
            substr[5] = '\0';
            latLong.lat = atof(substr);

            // Parse longitude: chars 33-37 (5 chars)
            for(i = 0; i < 5; i++) {
                if (33+i < strlen(record.recString))
                    substr[i] = *(record.recString + i + 33);
                else
                    substr[i] = ' ';
            }
            substr[5] = '\0';
            latLong.lng = atof(substr);

            locations.push_back(latLong);
            records.push_back(record);
            recNum++;
        }
        fclose(fp);
    }
    fclose(flist);
    return recNum;
}

void findLowest(std::vector<Record> &records, float *distances, int numRecords, int topN) {
    int i, j;
    float val;
    int minLoc;
    Record tempRec;
    float tempDist;

    if (topN > numRecords) topN = numRecords;

    for (i = 0; i < topN; i++) {
        minLoc = i;
        for (j = i; j < numRecords; j++) {
            val = distances[j];
            if (val < distances[minLoc]) minLoc = j;
        }

        tempRec = records[i];
        records[i] = records[minLoc];
        records[minLoc] = tempRec;

        tempDist = distances[i];
        distances[i] = distances[minLoc];
        distances[minLoc] = tempDist;

        records[i].distance = distances[i];
    }
}

int parseCommandline(int argc, char *argv[], char* filename, int *r, float *lat, float *lng,
                     int *q, int *t, int *p, int *d) {
    int i;
    if (2 > argc) return 1;
    strncpy(filename, argv[1], 99);
    filename[99] = '\0';

    // Initialize outputs
    *r = 10;
    *lat = 0.0f;
    *lng = 0.0f;
    *q = 0;
    *t = 0;
    *p = -1;
    *d = -1;

    char flag;

    for (i = 1; i < argc; i++) {
        if ('-' == argv[i][0]) {
            flag = argv[i][1];
            switch (flag) {
            case 'r':
                if (i+1 < argc) {
                    i++;
                    *r = atoi(argv[i]);
                }
                break;
            case 'l':
                if (i+1 < argc) {
                    if (argv[i][2] == 'a') {
                        *lat = atof(argv[i + 1]);
                    } else {
                        *lng = atof(argv[i + 1]);
                    }
                    i++;
                }
                break;
            case 'h':
                return 1;
                break;
            case 'q':
                *q = 1;
                break;
            case 't':
                *t = 1;
                break;
            case 'p':
                if (i+1 < argc) {
                    i++;
                    *p = atoi(argv[i]);
                }
                break;
            case 'd':
                if (i+1 < argc) {
                    i++;
                    *d = atoi(argv[i]);
                }
                break;
            case 'f':
                if (i+1 < argc) {
                    i++;
                    // data_folder handling via environment or global in original, simplified here
                    // We can set env var or just ignore as loadData uses getenv
                    setenv("DATA_FOLDER", argv[i], 1);
                }
                break;
            }
        }
    }

    // Logic check from original: if one is set, both must be set?
    // Original: if ((0 <= *d && 0 > *p) || (*p>=0 && 0 > *d)) return 1;
    if ((0 <= *d && 0 > *p) || (*p >= 0 && 0 > *d))
        return 1;

    return 0;
}

void printUsage() {
    printf("Nearest Neighbor Usage\n");
    printf("\n");
    printf("nearestNeighbor [filename] -r [int] -lat [float] -lng [float] [-hqt] [-p [int] -d [int]]\n");
    printf("\n");
    printf("example:\n");
    printf("$ ./nearestNeighbor filelist.txt -r 5 -lat 30 -lng 90\n");
    printf("\n");
    printf("filename     the filename that lists the data input files\n");
    printf("-r [int]     the number of records to return (default: 10)\n");
    printf("-lat [float] the latitude for nearest neighbors (default: 0)\n");
    printf("-lng [float] the longitude for nearest neighbors (default: 0)\n");
    printf("\n");
    printf("-h, --help   Display the help file\n");
    printf("-q           Quiet mode. Suppress all text output.\n");
    printf("-t           Print timing information.\n");
    printf("\n");
    printf("-p [int]     Choose the platform (must choose both platform and device)\n");
    printf("-d [int]     Choose the device (must choose both platform and device)\n");
    printf("\n");
    printf("\n");
    printf("Notes: 1. The filename is required as the first parameter.\n");
    printf("       2. If you declare either the device or the platform,\n");
    printf("          you must declare both.\n\n");
}

int main(int argc, char *argv[]) {
    std::vector<Record> records;
    float *recordDistances = NULL;

    std::vector<LatLong> locations;
    int i;

    char filename[100];
    int resultsCount = 10, quiet = 0, timing = 0, platform = -1, device = -1;
    float lat = 0.0, lng = 0.0;

    if (parseCommandline(argc, argv, filename, &resultsCount, &lat, &lng,
                         &quiet, &timing, &platform, &device)) {
        printUsage();
        return 0;
    }

    int numRecords = loadData(filename, records, locations);

    if (numRecords == 0) {
        if (!quiet) printf("No records loaded.\n");
        return 0;
    }

    if (!quiet) {
        printf("Number of records: %d\n", numRecords);
        printf("Finding the %d closest neighbors.\n", resultsCount);
    }

    if (numRecords < resultsCount) resultsCount = numRecords;

    cuda_init_context(platform, device, quiet);

    recordDistances = CudaFindNearestNeighbors(numRecords, locations, lat, lng, timing);

    if (recordDistances) {
        findLowest(records, recordDistances, numRecords, resultsCount);

        if (!quiet) {
            for (i = 0; i < resultsCount; i++) {
                printf("%s --> Distance=%f\n", records[i].recString, records[i].distance);
            }
        }
        free(recordDistances);
    }

    return 0;
}
